        ["909"] = { name = "Darkmoon Faire", description = "A carnival that showcases the weird and the extraordinary, located on a mysterious island only accessible for the first week of every month." },
        ["910"] = { name = "Brood of Nozdormu", description = "The descendants of the Bronze Dragonflight are the guardians of time and care little for the mortal races." },
        ["930"] = { name = "Exodar", description = "The naaru vessel that brought the draenei to Azeroth.  Though stranded in the Azuremyst Isles, it acts as a home city for this noble race." },
        ["932"] = { name = "The Aldor", description = "An ancient order of draenei priests once run by Velen, the Aldor are currently led by High Priestess Ishanah.  They are servants of the naaru in Shattrath City known as the Sha'tar.  Rivals of the Scryers." },
        ["933"] = { name = "The Consortium", description = "Led by Nexus-Prince Haramad, the Consortium is a loosely affiliated cartel of ethereal smugglers, traders and thieves that has come to Outland to benefit from its riches." },
        ["934"] = { name = "The Scryers", description = "Voren'thal the Seer leads the dissident blood elves who've rejected Kael'thas' path to power.  They've joined forces with the naaru of Shattrath City, much to the dismay of the Aldor." },
        ["935"] = { name = "The Sha'tar", description = "The Sha'tar are a group of powerful naaru who rule over a rebuilt Shattrath City.  With the help of the Aldor and the Scryers, they lead the battle against Illidan and the Burning Legion." },
        ["941"] = { name = "The Mag'har", description = "This reclusive group of brown-skinned orcs has escaped any form of demonic corruption.  They have retained their traditional way of life in the face of great changes in Outland." },
        ["942"] = { name = "Cenarion Expedition", description = "An exploratory force sent to Outland by the Cenarion Circle to study surviving life forms.  The Cenarion Expedition has quickly gained in size and autonomy since the opening of the Dark Portal." },
        ["946"] = { name = "Honor Hold", description = "Vestiges of the Sons of Lothar, veterans of the Alliance that first came into Draenor, have steadfastly held on to this Hellfire outpost.  They are now joined by the armies from Stormwind and Ironforge." },
        ["947"] = { name = "Thrallmar", description = "The expedition sent through the Dark Portal by Thrall has built a stronghold in Hellfire Peninsula.  Thrallmar serves as a base of operations for much of the Horde's activities in Outland." },
        ["967"] = { name = "The Violet Eye", description = "A secret sect of the Kirin Tor founded to spy on Medivh and his activities." },
        ["970"] = { name = "Sporeggar", description = "The sporelings are a mostly peaceful race of mushroom-men native to Outland. Their home is located in the southern bogs of Zangarmarsh." },
        ["978"] = { name = "Kurenai", description = "Draenei for \"redeemed.\"  These Broken have escaped the grasp of their various slavers in Outland and have made their home in Nagrand.  It is there that they seek to rediscover their destiny." },
        ["989"] = { name = "Keepers of Time", description = "The Keepers of Time are bronze dragons hand-picked by Nozdormu to watch over the Caverns of Time." },
        ["990"] = { name = "The Scale of the Sands", description = "A secretive subgroup of the Bronze Dragonflight, led by Soridormi, prime mate of Nozdormu." },
        ["1011"] = { name = "Lower City", description = "The refugees of Shattrath come from diverse backgrounds and races.  Word of helpful deeds spreads quickly among the Denizens of Lower City." },
        ["1012"] = { name = "Ashtongue Deathsworn", description = "The elite of the Broken tribe known as the Ashtongue, officially aligned with Illidan. The Deathsworn are Akama's most trusted lieutenants and are privy to their leader's mysterious motivations." },
        ["1015"] = { name = "Netherwing", description = "This unusual brood of dragons was spawned from the eggs of Deathwing's black dragonflight, and infused with raw nether-energies.  Now, they seek to find their identity beyond the shadows of their father's destructive heritage." },
        ["1031"] = { name = "Sha'tari Skyguard", description = "An airborne military force created by Shattrath City to deal with the threats that loom in the highest reaches of Outland." },
        ["1038"] = { name = "Ogri'la", description = "The enlightened denizens of Ogri'la have made their dwelling in the western Blade's Edge Mountains, where proximity to apexis crystals has caused them to transcend their brutish ogre nature." },
        ["1067"] = { name = "The Hand of Vengeance", description = "The Forsaken tasked by Sylvanas Windrunner with enacting Undercity's vengeance against Arthas by delivering the latest strain of their deadly Plague." },
        ["1068"] = { name = "Explorers' League", description = "This organization seeks to find the origin of the dwarven race by collecting Titan artifacts.  Their most recent research has led them to various archeological sites in Northrend." },
        ["1073"] = { name = "The Kalu'ak", description = "The tuskarr are a tough but peaceful people who derive their livelihood from fishing and whaling.  Their settlements have recently come under fierce attack and welcome any allies who would come to their aid." },
        ["1077"] = { name = "Shattered Sun Offensive", description = "Shattrath City's final push against Prince Kael'thas' operations in the Sunwell." },
        ["1090"] = { name = "Kirin Tor", description = "The mages and archmages running the city of Dalaran.  Faced with the rising threats of the Blue Dragonflight and the Scourge, they've transported their city to the heart of Northrend." },
        ["1091"] = { name = "The Wyrmrest Accord", description = "With the Blue Dragonflight's violent upheaval against all mortal users of magic, the remaining dragonflights have banded under the leadership of the Red Dragonflight to combat their wayward kin." },
        ["1098"] = { name = "Knights of the Ebon Blade", description = "Freed from the grasp of the Lich King, his former Death Knights have regrouped against him under the banner of Highlord Darion Mograine." },
        ["1104"] = { name = "Frenzyheart Tribe", description = "Driven from their lands by the Scourge, this fierce tribe of wolvar stumbled upon Sholazar Basin, where they intend to make their new home.  Their aggressive nature has put them at odds with the various gorloc tribes known collectively as the Oracles." },
        ["1105"] = { name = "The Oracles", description = "The gorlocs of Sholazar Basin are a race of reptilian creatures who see themselves as guardians of the titan technology that remains in the zone (though they understand little of it).  They find themselves in an escalating territorial war with the wolvar." },
        ["1106"] = { name = "Argent Crusade", description = "Led by Tirion Fordring, the Argent Crusade combines the reformed Order of the Silver Hand with the Argent Dawn in one final push against the forces of the Lich King." },
        ["1119"] = { name = "The Sons of Hodir", description = "The frost giants of the Storm Peaks are a war-like race that makes their home in Dun Niffelem." },
        ["1124"] = { name = "The Sunreavers", description = "Traditionally barred from Dalaran, the Horde has been accepted into the city through the efforts of Archmage Aethas Sunreaver.  His followers have taken up his name and watch over the ward known as Sunreaver's Sanctuary." },
        ["1126"] = { name = "The Frostborn", description = "This mysterious race of frost dwarves makes their home in the Storm Peaks.  They've recently befriended members of the Explorers' League and welcome Alliance members within their settlements." },
        ["1133"] = { name = "Bilgewater Cartel", description = "Run by the ruthless Trade Prince Gallywix, the Bilgewater Cartel is the most powerful trading company on the Isle of Kezan. From their headquarters at Bilgewater Port, the cartel dominates trade all over the South Seas." },
        ["1134"] = { name = "Gilneas", description = "The people of Gilneas are a nation of survivors.  Having walled themselves off from the rest of humanity, they must now face new threats from within." },
        ["1156"] = { name = "The Ashen Verdict", description = "Under a pact by Tirion Fordring and Darion Mograine, the Argent Crusade and the Knights of the Ebon Blade have set aside their differences during the attack on Icecrown Citadel until the Lich King is slain." },
        ["1158"] = { name = "Guardians of Hyjal", description = "Faced with the impending devastation of Mount Hyjal, the most powerful members of the Cenarion Circle have joined forces with their Emerald Dragonflight allies to fend off Ragnaros' elemental hordes and the Twilight's Hammer." },
        ["1171"] = { name = "Therazane", description = "The elemental plane of earth, Deepholm, is ruled by Therazane and her children, the Stone Lords.  After witnessing the devastation Deathwing and his followers caused her realm, Therazane treats all outsiders with open hostility." },
        ["1172"] = { name = "Dragonmaw Clan", description = "This wayward orc clan was once empowered by Deathwing himself to enslave red dragons, including Alexstrasza.  Currently less numerous and powerful, the Dragonmaw make their home in the Twilight Highlands." },
        ["1173"] = { name = "Ramkahen", description = "The cat-like people of Ramkahen are the descendants of the Tol'vir, guardians of Uldum.  Though they've lost their stone bodies, protecting the secrets of the titans is still a part of their rigid tradition." },
        ["1174"] = { name = "Wildhammer Clan", description = "The Wildhammer dwarves are known for their near-reckless courage as well as their unsurpassed gryphon-riding skills.  After losing their home of Grim Batol to a Dark Iron Curse, they've spread their dwellings around the Twilight Highlands." },
        ["1177"] = { name = "Baradin's Wardens", description = "Once led by Duke Reginald Baradin II, this fierce army has historic ties to the island stronghold of Tol Barad.  They have joined the forces of the Alliance in an effort to repeal the Horde invaders and gain control of this strategic island." },
        ["1178"] = { name = "Hellscream's Reach", description = "Hellscream's Reach is an elite Horde regiment comprised solely of veterans of multiple tours of duty.   Handpicked by Garrosh himself, he has commanded them to take complete control of Tol Barad.  Failure is not an option." },
        ["1204"] = { name = "Avengers of Hyjal", description = "Infuriated by the destruction wrought by the Lord of Flame, the Cenarion Circle seize the initiative, fighting back against Ragnaros and driving deep into the very heart of the Firelands." },
        ["1269"] = { name = "Golden Lotus", description = "This mysterious society of Pandaren intend to solve the Mogu problem once and for all." },
        ["1270"] = { name = "Shado-Pan", description = "The shadowy protectors of Pandaria's temples, the Shado-Pan are wrought with mystery." },
        ["1271"] = { name = "Order of the Cloud Serpent", description = "Guardians of the East Temple" },
        ["1272"] = { name = "The Tillers", description = "The Tillers are peaceful and productive pandaren, working with the land to feed the massive appetites of their people." },
        ["1302"] = { name = "The Anglers", description = "The Anglers are a group of Pandaren fisherman that hope to feed their people and grow their knowledge of fishing." },
        ["1337"] = { name = "The Klaxxi", description = "These Mantid Elders are untouched by the corruption and insanity that has overtaken the remainder of the Mantid Swarm. They seek to work with the races of Pandaria to restore their Queen to glory." },
        ["1359"] = { name = "The Black Prince", description = "Black Prince Wrathion is the last of the black dragons. He has been known to richly reward those who earn his trust and support his endeavors." },
        ["1375"] = { name = "Dominance Offensive", description = "Horde forces in Pandaria, stationed at Domination Point in Krasarang Wilds." },
        ["1376"] = { name = "Operation: Shieldwall", description = "Alliance forces in Pandaria, stationed at Lion's Landing in Krasarang Wilds." },
        ["1387"] = { name = "Kirin Tor Offensive", description = "Ignited by Jaina's fury, the Kirin Tor Offensive seek to seize Thunder Isle for the glory of the Alliance!" },
        ["1388"] = { name = "Sunreaver Onslaught", description = "Outcast from Dalaran, the Sunreaver Onslaught fight to obtain powerful mogu artifacts from among the ruins of Thunder Isle, and to secure their future if the Horde falls to anarchy." },
        ["1416"] = { name = "Akama's Trust", description = "Akama is distrustful of Warlocks after witnessing Illidan's fall to his own corruption, followed by the invasion of the Black Temple by Warlocks after the Cataclysm." },
        ["1435"] = { name = "Shado-Pan Assault", description = "These valorous Shado-Pan venture into the Throne of Thunder to vanquish the evil found within, and exact justice for the centuries of slavery they endured under the Thunder King's reign." },
        ["1445"] = { name = "Frostwolf Orcs", description = "The Frostwolf orcs of Frostfire Ridge are a tight-knit family of brutal warriors, well equipped to deal with the savage realities of Draenor." },
        ["1492"] = { name = "Emperor Shaohao", description = "Shaohao, the long lost Emperor of the Pandaren people, is a personage worthy of deep respect." },
        ["1515"] = { name = "Arakkoa Outcasts", description = "Working from the shadows, the Arakkoa Outcasts seek to bring a brighter tomorrow." },
        ["1710"] = { name = "Sha'tari Defense", description = "The defenders of Shattrath struggle to regain control of their capital city, having been betrayed from within." },
        ["1711"] = { name = "Steamwheedle Preservation Society", description = "The goblins of the Steamwheedle Preservation Society seek to liberate relics from the ogres of Nagrand with the noble intention of selling them to the highest bidder." },
        ["1731"] = { name = "Council of Exarchs", description = "Under the leadership of five powerful exarchs, the draenei of Draenor have prospered in a savage world." },
        ["1828"] = { name = "Highmountain Tribe", description = "The Highmountain Tribe has dwindled in numbers over the years, and with the drogbar threat looming, seek new allies to save their homeland." },
        ["1847"] = { name = "Hand of the Prophet", description = "Yrel has assembled the remaining Exarchs and is calling for a crusade in Velen's name. Together they are working to establish a foothold in Tanaan Jungle and to overthrow Gul'dan." },
        ["1848"] = { name = "Vol'jin's Headhunters", description = "Seeking to protect Azeroth with a decisive victory on Draenor, Warchief Vol'jin is assembling an elite team of champions to establish a foothold in Tanaan Jungle and to overthrow Gul'dan." },
        ["1849"] = { name = "Order of the Awakened", description = "Survivors of a grisly civil war, these beleaguered arakkoans hope the reclamation of apexis artifacts will hold the key to peacefully rebuilding their civilization." },
        ["1850"] = { name = "The Saberstalkers", description = "The treacherous wilds of Tanaan Jungle have attracted the craftiest hunters from both Azeroth and Draenor. To defeat the beasts of Tanaan, one must become a beast." },
        ["1859"] = { name = "The Nightfallen", description = "These exiled Nightborne elves suffer withdrawals after being cut off from the Nightwell. They oppose their people's alliance with the Legion and fight for some kind of redemption." },
        ["1883"] = { name = "Dreamweavers", description = "The druids and their allies in Val'sharah have guarded the Emerald Dream since time immemorial." },
        ["1894"] = { name = "The Wardens", description = "After Legion forces broke the Vault of the Wardens with the aid of Gul'dan, what few Wardens remain are determined to rebuild their prison and hunt down the terrifying beasts that were let loose when it fell." },
        ["1900"] = { name = "Court of Farondis", description = "The ghostly Court of Farondis and its allies continue the fight against an onslaught of invaders on the cursed island of Azsuna." },
        ["1948"] = { name = "Valarjar", description = "These are the chosen warriors of Odyn, sworn to his service in life and death." },
        ["2045"] = { name = "Armies of Legionfall", description = "The coalition of orders dedicated to defeating the Legion at the Tomb of Sargeras and Broken Shore." },
        ["2135"] = { name = "Chromie", description = "Chronormu (Chromie for short) has always been one of the more active, approachable bronze dragons. Strengthening your bond with her will increase her power in the Deaths of Chromie scenario." },
        ["2157"] = { name = "The Honorbound", description = "A special delegation of the Horde army, focused on disrupting Alliance operations in Kul Tiras." },
        ["2158"] = { name = "Voldunai", description = "Comprised of exiles and scavengers, the Voldunai use their knowledge of the sands to thrive where others would wither and die." },
        ["2160"] = { name = "Proudmoore Admiralty", description = "Masters of the sea and commanders of Azeroth's finest navy, the distinguished Proudmoore family has led Kul Tiras for decades from their seat of power in Boralus." },
        ["2161"] = { name = "Order of Embers", description = "An ancient Kul Tiran order resurrected to battle the threat of witchcraft, the Order of Embers fights with knowledge guiding their blades." },
        ["2162"] = { name = "Storm's Wake", description = "Home to farmers, craftsmen, soldiers, and the mysterious tidesages, the Storm's Wake seeks to reclaim Stormsong Valley and affirm their place in Kul Tiras." },
        ["2165"] = { name = "Army of the Light", description = "After the fall of Argus, the draenei's finest warriors followed the prime naaru Xe'ra across the cosmos in an eternal war to bring about the Legion's end. Since then, other survivors of the Burning Crusade have joined the ranks of the Lightforged." },
        ["2170"] = { name = "Argussian Reach", description = "Although many struggled to oppose the Burning Legion's conquest of Argus, not all were able to escape. Emboldened by the arrival of new allies, these refugees and outcasts stand united in their mission to reclaim their home." },
        ["2373"] = { name = "The Unshackled", description = "Oppressed by the Naga, these refugees have banded together to rise up and seize their freedom." },
        ["2391"] = { name = "Rustbolt Resistance", description = "The Rustbolt Resistance holds the line against King Mechagon and his evil plans." },
        ["2395"] = { name = "Honeyback Hive", description = "A species of bee known for their unusual size. While newcomers to Stormsong Valley, they quickly made their presence known to adventurers and insect enthusiasts alike." },
        ["2400"] = { name = "Waveblade Ankoan", description = "Oppressed by the Naga, these refugees have banded together to rise up and seize their freedom." },
        ["2407"] = { name = "The Ascended", description = "Kyrian who complete the arduous process of purging their mortal encumbrances are deemed worthy of the rite of ascension, earning their wings and pledging eternal service to the Archon." },
        ["2410"] = { name = "The Undying Army", description = "Long ago, the Primus established the five houses of Maldraxxus to build the ultimate fighting force. Through might, cleverness, and guile, this unyielding armada is pledged to defend the Shadowlands against all threats." },
        ["2413"] = { name = "Court of Harvesters", description = "After countless ages spent under the rule of Sire Denathrius, authority in Revendreth is now shared amongst the Court of Harvesters. These noble venthyr carry out the sacred duty of redeeming prideful souls." },
        ["2415"] = { name = "Rajani", description = "A group of mogu loyal to the titan keeper Ra, they are charged with defending the Engine of Nalak'sha from N'Zoth's minions." },
        ["2417"] = { name = "Uldum Accord", description = "A loose coalition of allies headed by the Tol'vir, the Uldum Accord was founded to protect the Forge of Origination from enemy forces." },
        ["2432"] = { name = "Ve'nari", description = "Ve'nari knows more about the Maw than anyone, and she might share a fraction of that information with you if you earn her regard." },
        ["2439"] = { name = "The Avowed", description = "Fiercely devoted to the Accuser, these archivists seek to restore and catalog the sinstones fragmented by the Lord Chamberlain and his Inquisitor allies." },
        ["2464"] = { name = "Court of Night", description = "The anima drought and Drust invasion consume the Winter Queen and Wild Hunt's attention, leaving the droman of the Court of Night to protect the wildseeds and defend their groves." },
        ["2465"] = { name = "The Wild Hunt", description = "Called to serve the Winter Queen in times of dire need, the Wild Hunt assembles the finest huntresses and hunters in all of Ardenweald. In the face of drought and peril, the Wild Hunt stands ready to defend the forest." },
        ["2470"] = { name = "Death's Advance", description = "The combined might of the Shadowlands covenants, brought forth to breach the Sanctum of Domination." },
        ["2472"] = { name = "The Archivists' Codex", description = "Korthian attendants have committed their existence to researching relics from across the Shadowlands. Led by their Archivist, they are dedicated to recovering the relics scattered across Korthia in the wake of the mawsworn invasion." },
        ["2478"] = { name = "The Enlightened", description = "Once members of Cartel Al, the Enlightened have abandoned the pursuit of profit and glory out of devotion to the First Ones. By earning their favor, the brokers may be willing to share the knowledge they have gleaned." },
        ["2503"] = { name = "Maruuk Centaur", description = "Centaur clans roam the Ohn'ahran Plains, where they follow the call of the wind and seek the thrill of the hunt." },
        ["2507"] = { name = "Dragonscale Expedition", description = "A joint expedition of the Explorers' League and Reliquary, this fearless group of adventurers, scholars, and crafters seek to uncover the many mysteries of the Dragon Isles." },
        ["2510"] = { name = "Valdrakken Accord", description = "Centered in their most ancient city, the Valdrakken Accord is the unified might of all dragonkind, seeking to protect not only their island home but all of Azeroth." },
        ["2511"] = { name = "Iskaara Tuskarr", description = "The Iskaara Tuskarr have been on the Dragon Isles for generations, living in harmony and telling tales of the world around them." },
        ["2517"] = { name = "Wrathion", description = "Long focused on protecting Azeroth, Wrathion's gaze has now turned to the future of the black dragonflight... and his destiny." },
        ["2518"] = { name = "Sabellian", description = "Sabellian has established a new generation of uncorrupt black dragons, and works to protect it at all costs." },
        ["2523"] = { name = "Dark Talons", description = "Led by the brave Scalecommander Cindrethresh, the Dark Talons were trained to be the secret weapon of the black dragonflight. Today, these dracthyr use their skills to turn the tide of any battle regardless of how outnumbered they are." },
        ["2524"] = { name = "Obsidian Warders", description = "Led by the stalwart Scalecommander Azurathel, the Obsidian Warders were trained to be the shield of the black dragonflight. Today these dracthyr use those skills to defend those most in need against overwhelming odds." },
        ["2526"] = { name = "Winterpelt Furbolg", description = "The Winterpelt Furbolg speak a language no one seems to understand. Perhaps more will be revealed in the future." },
        ["2550"] = { name = "Cobalt Assembly", description = "The Cobalt Assembly was once a place where blue dragons would conjure marvelous creations with arcane magic. Now it has fallen into the hands of the Sundered Flame who intend to use its magic for war." },
        ["2553"] = { name = "Soridormi", description = "Soridormi's timewalkers travel the timeways and defend our world against limitless alternatives. When our timeline is under temporal assault or falling apart, Soridormi is the commander who holds everything together." },
        ["2564"] = { name = "Loamm Niffen", description = "Underneath the Dragon Isles, deep in Zaralek Cavern, lies the niffen town of Loamm. The friendly traders there are renowned for their hospitality, sense of smell, and peculiar bartering trade system." },
        ["2570"] = { name = "Hallowfall Arathi", description = "The Arathi of the Hallowfall Expedition safeguard the star Beledar from the many threats found under Khaz Algar. Cut off from their overseas empire, they have built a new home with the strength of their faith in the Sacred Flame." },
        ["2574"] = { name = "Dream Wardens", description = "A coalition of various races ready to defend the Emerald Dream against any and all threats." },
        ["2590"] = { name = "Council of Dornogal", description = "Ruling from the Foundation Hall under the leadership of Councilward Merrix, the Council of Dornogal makes decisions affecting all earthen in the Isle of Dorn." },
        ["2594"] = { name = "The Assembly of the Deeps", description = "Throughout the Ringing Deeps, neglected machinery awaits repair. While Machine Speakers lend their technological acumen, kobolds scavenge parts left behind. Anyone wanting to explore and rebuild is welcome to help." },
        ["2600"] = { name = "The Severed Threads", description = "Queen Ansurek's tumultuous reign has not been without its detractors. The Severed Threads work cleverly and quietly behind the scenes to unravel the tapestry of Ansurek's iron rule from within." },
        ["2601"] = { name = "The Weaver", description = "Once the Royal Weaver, the Widow Arak'nai now carefully watches her former home with a critical eye. With a network of weave-rats and spies at her disposal, there is little that escapes her notice." },
        ["2605"] = { name = "The General", description = "Once the most renowned military leader in Azj-Kahet, Anub'azal has been passed over in favor of one of Ansurek's beloved Ascended. This simply will not stand." },
        ["2607"] = { name = "The Vizier", description = "Perched in the most dangerous position of all, Executor Nizrek spends his days as Queen Ansurek's most loyal advisor. Fortunately, Ansurek has yet to discover that the rest of his time is spent trying to end her reign." },
        ["2615"] = { name = "Azerothian Archives", description = "A charter group of scholars from the Dragonscale Expedition dedicated to the preservation of the antiquities for future generations." },
        ["2653"] = { name = "The Cartels of Undermine", description = "Undermine isn't like other towns. There are no kings or chiefs, just cartels. Everyone wants to be part of the cartels. It's even better than being a king, because you can only have one king. But Undermine's got a lot of cartels, and they all need a pal." },
        ["2658"] = { name = "The K'aresh Trust", description = "A coalition of cartels from brokers and ethereals formed with an impossible goal. To save a facet of their destroyed world from the All-Devouring." },
        ["2671"] = { name = "Venture Company", description = "Venture Company doesn't have the best rep in town, but no one harvests, mines, or drills faster. You want nice? Find a book club. You want raw material? Venture's got you covered." },
        ["2673"] = { name = "Bilgewater Cartel", description = "The Bilgewater Cartel has had more ups and downs than most, but no one can build and invent like they can. From cities to pool toys to [CLASSIFIED], Bilgewater builds it best." },
        ["2675"] = { name = "Blackwater Cartel", description = "Blackwater Cartel is new to the cart, formerly plying the seas as pirates. But they are already making waves with shipping and luxury vacations. They can move any cargo, anywhere, any time, and now it's all nice and legal." },
        ["2677"] = { name = "Steamwheedle Cartel", description = "Steamwheedle may be the oldest and largest cartel in Undermine. They have had their hands in almost every industry and their reach spans Azeroth and beyond. These days, with the rise of Noggenfogger, it's the alchemy that they are known for." },
        ["2685"] = { name = "Gallagio Loyalty Rewards Club", description = "The Gallagio is under new management, well it will be. And when it is, you want to be on their good side right? So, make the Gallagio a better place and make some new friends." },
        ["2688"] = { name = "Flame's Radiance", description = "When Hallowfall comes under threat and the army stretched thin, a call to arms is issued to those with the strength to wield a weapon and Flame's Radiance is formed. All allies are welcome to join in Hallowfall's defense." },
        ["2696"] = { name = "Amani Tribe", description = "The Amani conquered and claimed the majority of Eastern Kingdoms for thousands of years, but were forced back into current-day Zul'Aman once the elves and humans colonized the land themselves." },
        ["2699"] = { name = "The Singularity", description = "In the vortex of terror and violence that is the Voidstorm, few have the mettle to survive. The Singularity, gathered by Magister Umbric and the ren'dorei, encompasses any who would brave this fearsome land to stand up to Xal'atath." },
        ["2704"] = { name = "Hara'ti", description = "Called to Harandar by the echo of their Goddess' song, the Hara'ti watch over her cradle in hopes that she may one day return." },
        ["2710"] = { name = "Silvermoon Court", description = "Through elegance, intellect, and political precision, the Court ensures that Silvermoon City's light shines eternally radiant, and distinctly its own." },
        ["2711"] = { name = "Magisters", description = "Scholars, arcanists, and politicians of Silvermoon City, with intellects sharpened by hundreds of years of study." },
        ["2712"] = { name = "Blood Knights", description = "Silvermoon City's elves-at-arms. Stalwart heroes and chosen champions of the sun, they follow Lady Liadrin into battle to smite the foes of the Sin'dorei." },
        ["2713"] = { name = "Farstriders", description = "Elite rangers of the Sin'dorei, formally tasked with guarding the forests, borders, and wildlands of the Eversong Woods." },
        ["2714"] = { name = "Shades of the Row", description = "12.0 Z1 Eversong - Court Friendship Faction" },
        ["2736"] = { name = "Manaforge Vandals", description = "While the K'aresh Trust works to unite the people of their dying star, some members prefer a more direct approach. Using all method of covert and under-handed tactics, the Manaforge Vandals seek to dismantle Salhadaar's forces by any means necessary." },
        ["2770"] = { name = "Slayer's Duellum", description = "Deep within the Voidstorm, the war between Vidious and Ziadan rages on." },
    },
    missing = {
        2544,
    },
}
